372	export const ResourceYAMLEditor: React.FC<ResourceYAMLEditorProps> = ({
373	  initialResource,
374	  header,
375	  onSave,
376	}) => {
377	  const isDarkTheme = useTheme();
378	  const containerHeight = document.getElementById("editor-content-container")?.clientHeight || 800;
379	  const footerHeight = document.getElementById("editor-toggle-footer")?.clientHeight || 0;
380	  return (<>
